import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldAlert, BarChart3, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_OFFLINE"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ ticker: t, price: Math.floor(Math.random() * 2000) + 500, change: 0.00 })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 8;
                return { ...s, price: parseFloat((s.price + move).toFixed(2)), change: parseFloat(move.toFixed(2)) };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={pageBackground}>
            <div style={centeredContainer}>
                {/* ── Flush Top Section ── */}
                <div style={headerContainer}>
                    <div style={navRow}>
                        <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={navBtn}>
                            <ChevronLeft size={18}/> PREV
                        </button>
                        <div style={nodeTitleBox}>
                            <Box size={14} color="var(--accent-primary)" />
                            <span style={nodeText}>{activeNode ? activeNode.goal : 'INITIALIZING...'}</span>
                            <span style={nodeCounter}>{currentIndex + 1} / {history.length}</span>
                        </div>
                        <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={navBtn}>
                            NEXT <ChevronRight size={18}/>
                        </button>
                    </div>

                    <div style={analyticsRow}>
                        <div style={statCard}>
                            <BarChart3 size={14} color="var(--accent-primary)" />
                            <div style={progressBar}><div style={progressFill(activeNode?.risk_score || 50)} /></div>
                            <span style={statLabel}>RISK: {activeNode?.risk_score}%</span>
                        </div>
                        <div style={statCard}>
                            <ShieldAlert size={14} color="#ef4444" />
                            <span style={statLabel}>SECURED</span>
                        </div>
                        <div style={connectionStatus(isConnected)}>
                            <Activity size={12} /> {isConnected ? 'LIVE' : 'OFFLINE'}
                        </div>
                    </div>
                </div>

                {/* ── Scrollable Area with Removed Padding ── */}
                <div style={scrollArea}>
                    <div style={tickerGrid}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardHeader}>
                                    <span style={tickerName}>{stock.ticker}</span>
                                    <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceText}>₹{stock.price.toLocaleString()}</div>
                                <div style={changeText(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    {stock.change >= 0 ? '+' : ''}{stock.change}%
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

/* --- Refined Visual Styles (Zero Padding focused) --- */
const pageBackground = { 
    height: 'calc(100vh - 70px)', 
    background: '#07080a', 
    display: 'flex', 
    justifyContent: 'center', 
    padding: '0' // Removed outer page padding
};

const centeredContainer = { 
    width: '100%',
    maxWidth: '1200px', 
    display: 'flex', 
    flexDirection: 'column', 
    background: '#0a0b0e', 
    borderLeft: '1px solid #1a1d23',
    borderRight: '1px solid #1a1d23',
    overflow: 'hidden'
};

const headerContainer = { 
    padding: '1rem 1.5rem', // Tightened header padding
    background: 'rgba(255,255,255,0.01)', 
    borderBottom: '1px solid #1a1d23' 
};

const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' };
const navBtn = { background: 'none', border: 'none', color: 'var(--accent-primary)', cursor: 'pointer', fontSize: '0.65rem', fontWeight: 800, fontFamily: 'monospace', display: 'flex', alignItems: 'center', gap: '4px' };
const nodeTitleBox = { display: 'flex', alignItems: 'center', gap: '12px', background: '#111318', padding: '6px 12px', borderRadius: '4px', border: '1px solid #1a1d23' };
const nodeText = { fontSize: '0.75rem', fontWeight: 700, color: '#fff' };
const nodeCounter = { fontSize: '0.55rem', color: 'var(--accent-primary)', background: 'rgba(16,185,129,0.1)', padding: '2px 5px', borderRadius: '3px' };

const analyticsRow = { display: 'flex', gap: '1.5rem', alignItems: 'center' };
const statCard = { display: 'flex', alignItems: 'center', gap: '8px', background: 'none', padding: '0', border: 'none' };
const statLabel = { fontSize: '0.6rem', fontWeight: 800, color: '#666' };
const progressBar = { width: '50px', height: '3px', background: '#1a1d23', borderRadius: '2px' };
const progressFill = (val) => ({ width: `${val}%`, height: '100%', background: 'var(--accent-primary)', borderRadius: '2px' });
const connectionStatus = (online) => ({ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.55rem', fontWeight: 900, color: online ? '#10b981' : '#ef4444' });

const scrollArea = { 
    flex: 1, 
    padding: '1.5rem', // Content padding reduced
    overflowY: 'auto' 
};

const tickerGrid = { 
    display: 'grid', 
    gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', 
    gap: '1rem' // Reduced gap between cards
};

const stockCard = (up) => ({ 
    padding: '1.2rem', 
    background: '#111318', 
    border: '1px solid #1a1d23', 
    borderRadius: '12px', 
    borderLeft: `3px solid ${up ? '#10b981' : '#ef4444'}`,
    transition: 'border 0.2s'
});

const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '0.8rem' };
const tickerName = { fontSize: '0.75rem', fontWeight: 900, color: 'var(--accent-primary)', fontFamily: 'monospace' };
const priceText = { fontSize: '1.6rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeText = (up) => ({ color: up ? '#10b981' : '#ef4444', fontSize: '0.75rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '5px', marginTop: '5px' });

export default LiveMarketPage;
